# Generar archivos individuales
for case in CASES:
    filepath = os.path.join(CASES_DIR, f"{case['id']}.json")
    data = {
        "id":           case["id"],
        "title":        case["title"],
        "court":        case["court"],
        "year":         case["year"],
        "branch":       case["branch"],
        "text":         case["text"],
        "source":       "SAIJ / CSJN — dominio público",
        "source_url":   case["source_url"],
        "annotation_slots": 3,
    }
    with open(filepath, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

# Generar índice
index = {
    "version": "1.0",
    "created": "2026-04-02",
    "total_cases": len(CASES),
    "source": "Public Argentine legal materials (SAIJ, CSJN) — all in public domain",
    "cases": [
        {
            "id":                 c["id"],
            "title":              c["title"],
            "court":              c["court"],
            "year":               c["year"],
            "branch":             c["branch"],
            "source_url":         c["source_url"],
            "file":               f"cases/{c['id']}.json",
            "expected_difficulty": c["difficulty"],
            "notes":              "",
        }
        for c in CASES
    ],
}

with open(os.path.join(CASES_DIR, "cases_index.json"), "w", encoding="utf-8") as f:
    json.dump(index, f, ensure_ascii=False, indent=2)

print(f"Generated {len(CASES)} case files + cases_index.json")
